+            "user": response.data,
+            "includes": response.includes
+        }))
+    }
+
+    // ─────────────────────────────────────────────────────────────────────────
+    // Tweet operations
+    // ─────────────────────────────────────────────────────────────────────────
+
+    async fn op_tweet_get(&self, args: Value) -> Result<Value, FcpError> {
